// Revisión técnica solar con Claude Haiku.
// Requiere env: ANTHROPIC_API_KEY
// Input body: { context: 'review'|'sizing'|'explain', payload: {...} }

const src = $input.first().json;
const body = src.body || src;
const context = (body.context || 'review').toString();
const payload = body.payload || {};

const AKEY = $env.ANTHROPIC_API_KEY;
if (!AKEY) throw new Error('Falta env ANTHROPIC_API_KEY');

const system = 'Eres un ingeniero eléctrico especializado en sistemas solares fotovoltaicos en Colombia. Conoces RETIE, CREG 038/2014, CREG 174/2021 (AGPE), Ley 1715, estándares NEC/IEC. Analiza el dimensionamiento que te envía el cotizador y devuelve observaciones concretas, accionables y técnicas. Usa español neutro.';

const userPrompt = `Contexto: ${context}\n\nSistema a revisar (JSON):\n${JSON.stringify(payload, null, 2)}\n\nDevuelve SOLO JSON válido con esta forma exacta (sin markdown):\n{\n  \"summary\": string,\n  \"findings\": string[],\n  \"warnings\": string[],\n  \"suggestions\": string[]\n}\n\nReglas:\n- summary: 1-2 frases, lenguaje ejecutivo.\n- findings: 2-5 observaciones técnicas clave (dimensionamiento, cobertura, compatibilidad eléctrica, normativa).\n- warnings: alertas críticas (voc fuera de rango, banco subdimensionado, incompatibilidad de voltaje, excedentes fuera de AGPE, etc). Vacío si no hay.\n- suggestions: 2-4 acciones recomendadas específicas.\n- NO inventes valores. Trabaja solo con los datos del payload.`;

const r = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': AKEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json',
  },
  body: {
    model: 'claude-haiku-4-5-20251001',
    max_tokens: 1024,
    system,
    messages: [{ role: 'user', content: userPrompt }],
  },
  json: true,
});

const text = (r.content || []).map(c => c.text || '').join('\n').trim();
const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Claude no devolvió JSON parseable');
let parsed;
try { parsed = JSON.parse(m[0]); } catch (e) { throw new Error('JSON inválido de Claude: ' + e.message); }

const usage = r.usage || {};
return [{ json: {
  summary: parsed.summary || '',
  findings: Array.isArray(parsed.findings) ? parsed.findings : [],
  warnings: Array.isArray(parsed.warnings) ? parsed.warnings : [],
  suggestions: Array.isArray(parsed.suggestions) ? parsed.suggestions : [],
  provider: 'claude-haiku-4-5',
  tokens: { in: usage.input_tokens || 0, out: usage.output_tokens || 0 },
} }];
